import{d as s}from"./index-CjyuK5MW.js";class t{async list(e=!1){return(await s.get("/warehouses",{params:{includeInactive:e}})).data}async getById(e){return(await s.get(`/warehouses/${e}`)).data}async getDefault(){return(await s.get("/warehouses/default")).data}async create(e){return(await s.post("/warehouses",e)).data}async update(e,a){return(await s.put(`/warehouses/${e}`,a)).data}async delete(e){return(await s.delete(`/warehouses/${e}`)).data}}const p=new t;export{p as w};
